{"command": "python3 -c "
# More extensive testing
def test_identity(C3, C2):
    for x in range(C3 + 1):
        lhs = (C3 - x) & C2
        rhs = (C3 & C2) - (x & C2)
        if lhs != rhs:
            return False, x, lhs, rhs
    return True, None, None, None

# Test various combinations
failures = []
for C3 in range(1, 256):
    for C2 in range(1, 256):
        ok, x, lhs, rhs = test_identity(C3, C2)
        if not ok:
            failures.append((C3, C2, x, lhs, rhs))
            if len(failures) >= 10:
                break
    if len(failures) >= 10:
        break

if failures:
    print('Counterexamples found:')
    for f in failures[:5]:
        print(f'  C3={f[0]}, C2={f[1]}, X={f[2]}: LHS={f[3]}, RHS={f[4]}')
else:
    print('No counterexamples found for C3, C2 in [1, 255]')
""}

