{"command": "python3 -c "
def test_identity(C3, C2):
    for x in range(C3 + 1):
        lhs = (C3 - x) & C2
        rhs = (C3 & C2) - (x & C2)
        if lhs != rhs:
            return False
    return True

# Check condition: (C2 & ~C3) == 0
print('Testing condition (C2 & ~C3) == 0:')
for C3 in range(1, 64):
    for C2 in range(1, 64):
        identity_holds = test_identity(C3, C2)
        condition_holds = (C2 & ~C3) == 0
        if identity_holds != condition_holds:
            print(f'Mismatch: C3={C3}, C2={C2}, identity={identity_holds}, condition={condition_holds}')

print('Condition check complete')
""}

